    @Nested
    inner class `Issue - Mutable collection properties in objects` {
        @Test
        fun `Given an object with MutableMap property name in lower camel case then do not emit`() {
            val code =
                """
                object DumObjectName {
                    val someMap: MutableMap<String, String> = mutableMapOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given an object with MutableList property name in lower camel case then do not emit`() {
            val code =
                """
                object DumObjectName {
                    val someList: MutableList<Int> = mutableListOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given an object with MutableSet property name in lower camel case then do not emit`() {
            val code =
                """
                object DumObjectName {
                    val someSet: MutableSet<String> = mutableSetOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given an object with MutableMap property name in screaming snake case then do emit`() {
            val code =
                """
                object DumObjectName {
                    val SOME_MAP: MutableMap<String, String> = mutableMapOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code)
                .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should start with a lowercase letter and use camel case")
        }

        @Test
        fun `Given an object with immutable Map property name in screaming snake case then do not emit`() {
            val code =
                """
                object DumObjectName {
                    val IMMUTABLE_MAP: Map<String, String> = mapOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a companion object with MutableMap property name in lower camel case then do not emit`() {
            val code =
                """
                class Foo {
                    companion object {
                        val someMap: MutableMap<String, String> = mutableMapOf()
                    }
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a companion object with MutableMap property name in screaming snake case then do emit`() {
            val code =
                """
                class Foo {
                    companion object {
                        val SOME_MAP: MutableMap<String, String> = mutableMapOf()
                    }
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code)
                .hasLintViolationWithoutAutoCorrect(3, 13, "Property name should start with a lowercase letter and use camel case")
        }

        @Test
        fun `Given an object with mutable collection in custom getter then do not emit`() {
            val code =
                """
                object DumObjectName {
                    val someMap: MutableMap<String, String>
                        get() = mutableMapOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }
    }
}"}

